 import { Link } from "react-router-dom";

function PostCard({ post }) {
  return (
    <Link
      to={`/post/${post.id}`}
      style={{
        textDecoration: "none",
        color: "inherit"
      }}
    >
      <div className="post-card">

        <img
          src={post.image}
          alt={post.title}
        />

        <div className="post-content">

          <span className="tag">
            Technology
          </span>

          <h3>{post.title}</h3>

          <p>{post.content}</p>

          <div className="post-footer">

            <span>
              👤 {post.author}
            </span>

            <span>
              ❤️ {post.likes}
            </span>

            <span>
              💬 {post.comments}
            </span>

          </div>

          <button className="read-btn">
            Read More →
          </button>

        </div>

      </div>
    </Link>
  );
}

export default PostCard;
